class UserService {
  #cache = new Map<string, User>();
  #apiClient: ApiClient;

  constructor(apiClient: ApiClient) {
    this.#apiClient = apiClient;
  }

  async getUser(id: string): Promise<User> {
    if (this.#cache.has(id)) return this.#cache.get(id)!;
    const user = await this.#apiClient.getUser(id);
    this.#cache.set(id, user);
    return user;
  }
  // #cache and #apiClient genuinely inaccessible outside class
}

import { flushSync } from 'react-dom';

function Chat() {
  const containerRef = useRef<HTMLDivElement>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const sendMessage = (text: string) => {
    flushSync(() => {
      setMessages(m => [...m, { id: nanoid(), text }]);
    });
    // After flushSync, DOM is updated - scroll to bottom
    containerRef.current?.scrollTo({ top: containerRef.current.scrollHeight });
  };
  return <div ref={containerRef}>...</div>;
}

interface DataGridProps<T> {
  data: T[];
  columns: {
    id: string;
    header: string;
    render: (item: T) => React.ReactNode;
  }[];
}

function DataGrid<T>({ data, columns }: DataGridProps<T>) {
  return (
    <table>
      <tbody>
        {data.map(item => (
          <tr key={(item as any).id}>
            {columns.map(col => (
              <td key={col.id}>{col.render(item)}</td>
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  );
}

