class QueryBuilder<TFrom = never, TWhere = false> {
  private fromTable?: string;
  private whereClauses: string[] = [];

  from<T extends string>(table: T): QueryBuilder<T, TWhere> {
    this.fromTable = table;
    return this as any;
  }

  where(this: QueryBuilder<string, TWhere>, clause: string): QueryBuilder<TFrom, true> {
    this.whereClauses.push(clause);
    return this as any;
  }

  build(this: QueryBuilder<string, any>): string {
    return `SELECT * FROM ${this.fromTable}${this.whereClauses.length ? ' WHERE ' + this.whereClauses.join(' AND ') : ''}`;
  }
}

